# For loop for getting data

# 119th Congress (to-do: increase Congress)
for i in range (1):
    congress = 119-i

    # For sessions 1 & 2
    for j in range(2):
        session = j+1
        year = 1786+congress*2 + session

        senate_base_url = f"https://www.senate.gov/legislative/LIS/roll_call_votes/vote{congress}{session}/vote_{congress}_{session}_00{{:03d}}.xml"
        senate_output_json = f"senate_votes_{congress}_{session}.json"

        house_base_url = f"https://clerk.house.gov/evs/{year}/roll{{:03d}}.xml"
        house_output_json = f"house_votes_{congress}_{session}.json"
        
        # Limit function call to most recent data or new historical data
        if (
            (congress == 119 and session == 2)
            or not os.path.isfile(f"silver/{senate_output_json}")
            or not os.path.isfile(f"silver/{house_output_json}")
        ):
            getting_voting_data_from_xml_urls(senate_base_url, senate_output_json, "Senate")
            getting_voting_data_from_xml_urls(house_base_url, house_output_json, "House")